class Solution {
    public boolean checkRecord(String s) {
        int absences = 0;
        int lateStreak = 0;
        for (char c : s.toCharArray()) {
            if (c == 'A') absences++;
            if (c == 'L') lateStreak++;
            else lateStreak = 0;
            if (absences >= 2 || lateStreak >= 3) return false;
        }
        return true;
    }
}
```
